-- Admission, Room and Bed Management migration. Run once as HOSPITAL_APP after V010.
-- Existing legacy admission rows must be discharged/cancelled or mapped manually before making new columns NOT NULL.
CREATE SEQUENCE ADMISSION_NUMBER_SEQ START WITH 1 INCREMENT BY 1 NOCYCLE CACHE 20;
CREATE TABLE ROOMS (ROOM_ID NUMBER GENERATED BY DEFAULT AS IDENTITY,ROOM_NUMBER VARCHAR2(30) NOT NULL,ROOM_TYPE VARCHAR2(20) NOT NULL,FLOOR_NUMBER NUMBER(3) NOT NULL,DEPARTMENT_ID NUMBER,DAILY_RATE NUMBER(14,2) NOT NULL,STATUS VARCHAR2(20) DEFAULT 'ACTIVE' NOT NULL,CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,UPDATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,CONSTRAINT PK_ROOMS PRIMARY KEY(ROOM_ID),CONSTRAINT UK_ROOMS_NUMBER UNIQUE(ROOM_NUMBER),CONSTRAINT FK_ROOMS_DEPT FOREIGN KEY(DEPARTMENT_ID) REFERENCES DEPARTMENTS(DEPARTMENT_ID),CONSTRAINT CK_ROOMS_TYPE CHECK(ROOM_TYPE IN('GENERAL','SEMI_PRIVATE','PRIVATE','ICU','EMERGENCY','MATERNITY','PEDIATRIC','OTHER')),CONSTRAINT CK_ROOMS_RATE CHECK(DAILY_RATE>=0),CONSTRAINT CK_ROOMS_STATUS CHECK(STATUS IN('ACTIVE','INACTIVE','MAINTENANCE')));
CREATE TABLE BEDS (BED_ID NUMBER GENERATED BY DEFAULT AS IDENTITY,ROOM_ID NUMBER NOT NULL,BED_NUMBER VARCHAR2(30) NOT NULL,STATUS VARCHAR2(20) DEFAULT 'AVAILABLE' NOT NULL,CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,UPDATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,CONSTRAINT PK_BEDS PRIMARY KEY(BED_ID),CONSTRAINT UK_BEDS_ROOM_NUMBER UNIQUE(ROOM_ID,BED_NUMBER),CONSTRAINT FK_BEDS_ROOM FOREIGN KEY(ROOM_ID) REFERENCES ROOMS(ROOM_ID),CONSTRAINT CK_BEDS_STATUS CHECK(STATUS IN('AVAILABLE','OCCUPIED','MAINTENANCE','INACTIVE')));
ALTER TABLE ADMISSIONS ADD (ADMISSION_NUMBER VARCHAR2(50),DOCTOR_ID NUMBER,DEPARTMENT_ID NUMBER,APPOINTMENT_ID NUMBER,BED_ID NUMBER,EXPECTED_DISCHARGE_DATE DATE,ACTUAL_DISCHARGE_DATE TIMESTAMP,ADMISSION_REASON VARCHAR2(1000),DISCHARGE_SUMMARY VARCHAR2(4000),CREATED_BY NUMBER);
UPDATE ADMISSIONS SET ACTUAL_DISCHARGE_DATE=DISCHARGE_DATE WHERE DISCHARGE_DATE IS NOT NULL;
ALTER TABLE ADMISSIONS DROP COLUMN DISCHARGE_DATE;
ALTER TABLE ADMISSIONS DROP CONSTRAINT CK_ADMISSIONS_STATUS;
ALTER TABLE ADMISSIONS ADD CONSTRAINT CK_ADMISSIONS_STATUS CHECK(STATUS IN('ADMITTED','TRANSFERRED','DISCHARGED','CANCELLED'));
ALTER TABLE ADMISSIONS ADD CONSTRAINT UK_ADMISSIONS_NUMBER UNIQUE(ADMISSION_NUMBER);
ALTER TABLE ADMISSIONS ADD CONSTRAINT FK_ADMISSIONS_DOCTOR FOREIGN KEY(DOCTOR_ID) REFERENCES DOCTORS(DOCTOR_ID);
ALTER TABLE ADMISSIONS ADD CONSTRAINT FK_ADMISSIONS_DEPT FOREIGN KEY(DEPARTMENT_ID) REFERENCES DEPARTMENTS(DEPARTMENT_ID);
ALTER TABLE ADMISSIONS ADD CONSTRAINT FK_ADMISSIONS_APPT FOREIGN KEY(APPOINTMENT_ID) REFERENCES APPOINTMENTS(APPOINTMENT_ID);
ALTER TABLE ADMISSIONS ADD CONSTRAINT FK_ADMISSIONS_BED FOREIGN KEY(BED_ID) REFERENCES BEDS(BED_ID);
ALTER TABLE ADMISSIONS ADD CONSTRAINT FK_ADMISSIONS_CREATOR FOREIGN KEY(CREATED_BY) REFERENCES USERS(USER_ID);
CREATE TABLE ADMISSION_TRANSFERS (TRANSFER_ID NUMBER GENERATED BY DEFAULT AS IDENTITY,ADMISSION_ID NUMBER NOT NULL,FROM_BED_ID NUMBER NOT NULL,TO_BED_ID NUMBER NOT NULL,TRANSFER_REASON VARCHAR2(500) NOT NULL,TRANSFERRED_BY NUMBER NOT NULL,TRANSFERRED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,CONSTRAINT PK_ADM_TRANSFERS PRIMARY KEY(TRANSFER_ID),CONSTRAINT FK_ADM_TR_ADMISSION FOREIGN KEY(ADMISSION_ID) REFERENCES ADMISSIONS(ADMISSION_ID),CONSTRAINT FK_ADM_TR_FROM_BED FOREIGN KEY(FROM_BED_ID) REFERENCES BEDS(BED_ID),CONSTRAINT FK_ADM_TR_TO_BED FOREIGN KEY(TO_BED_ID) REFERENCES BEDS(BED_ID),CONSTRAINT FK_ADM_TR_USER FOREIGN KEY(TRANSFERRED_BY) REFERENCES USERS(USER_ID));
CREATE UNIQUE INDEX UK_ADM_ACTIVE_PATIENT ON ADMISSIONS(CASE WHEN STATUS IN('ADMITTED','TRANSFERRED') THEN PATIENT_ID END);
CREATE UNIQUE INDEX UK_ADM_ACTIVE_BED ON ADMISSIONS(CASE WHEN STATUS IN('ADMITTED','TRANSFERRED') THEN BED_ID END);
CREATE INDEX IDX_ADMISSIONS_DOCTOR ON ADMISSIONS (DOCTOR_ID);
CREATE INDEX IDX_ADMISSIONS_BED ON ADMISSIONS (BED_ID);
CREATE INDEX IDX_ADMISSIONS_STATUS ON ADMISSIONS (STATUS);
CREATE INDEX IDX_ADMISSIONS_DATE ON ADMISSIONS (ADMISSION_DATE);
CREATE INDEX IDX_BEDS_STATUS ON BEDS (STATUS);
CREATE INDEX IDX_ROOMS_STATUS ON ROOMS (STATUS);
